define double @fmul_tan_cos_fpmath_metadata_preservation(double %a) {
  %tan = call contract double @llvm.tan.f64(double %a)
  %cos = call contract double @llvm.cos.f64(double %a)
  %res = fmul contract double %tan, %cos, !fpmath !0
